import React, { useEffect, useState } from 'react';
import axios from 'axios';
import SellerBadge from '../components/SellerBadge';

const Marketplace = () => {
  const [items, setItems] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  const handleBuy = async (item) => {
    const buyerId = localStorage.getItem('userId');
    if (!buyerId) {
      alert("Please log in to buy items.");
      return;
    }

    try {
      await axios.post('http://localhost:5000/api/transactions/buy', {
        itemId: item._id,
        buyerId: buyerId,
        sellerId: item.sellerId,
        price: item.price,
        title: item.title
      });

      alert(`Success! You bought the ${item.title}.`);
      setItems(items.filter(i => i._id !== item._id));
    } catch (err) {
      console.error(err);
      alert("Transaction failed.");
    }
  };

  useEffect(() => {
    const fetchItems = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/items/all');
        setItems(res.data);
      } catch (err) {
        console.error("Error fetching items", err);
      }
    };
    fetchItems();
  }, []);

  const filteredItems = items.filter(item => 
    item.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div style={pageWrapper}>
      <header style={headerStyle}>
        <h2 style={titleStyle}>Vintage Marketplace</h2>
        <p style={subtitleStyle}>Discover unique treasures from verified sellers.</p>
      </header>
      
      {/* Search Bar Container */}
      <div style={searchContainer}>
        <input 
          type="text" 
          placeholder="Search by name or category (e.g. Jackets)..." 
          style={searchStyle}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div style={gridStyle}>
        {filteredItems.map((item) => (
          <div key={item._id} style={cardStyle}>
            {/* Image Container with fixed Aspect Ratio */}
            <div style={imageWrapper}>
              <img src={item.imageUrl} alt={item.title} style={imageStyle} />
            </div>

            <div style={cardContent}>
              <div style={itemHeader}>
                <h3 style={itemTitle}>{item.title}</h3>
                <span style={itemPrice}>${item.price}</span>
              </div>
              <p style={itemCategory}>{item.category}</p>
              
              <div style={sellerRow}>
                <div style={sellerInfo}>
                  <small style={sellerText}>Curated by {item.sellerEmail.split('@')[0]}</small>
                  {item.sellerId?.isVerifiedSeller && (
                    <div style={{ marginLeft: '5px', transform: 'scale(0.8)' }}>
                      <SellerBadge isVerified={true} />
                    </div>
                  )}
                </div>
              </div>

              <button onClick={() => handleBuy(item)} style={buyButtonStyle}>
                Buy Now
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- Styles ---

const pageWrapper = {
  padding: '60px 80px',
  backgroundColor: '#fdfcf0', // Consistent pastel cream
  minHeight: '100vh',
  fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif",
};

const headerStyle = {
  marginBottom: '40px',
};

const titleStyle = {
  fontSize: '32px',
  fontWeight: '300',
  color: '#202124',
  margin: '0 0 8px 0',
};

const subtitleStyle = {
  color: '#5f6368',
  fontSize: '16px',
  margin: 0,
};

const searchContainer = {
  marginBottom: '40px',
  maxWidth: '600px',
};

const searchStyle = { 
  width: '100%', 
  padding: '14px 20px', 
  fontSize: '16px',
  borderRadius: '24px', // Rounded "pill" style like Google Search
  border: '1px solid #dadce0', 
  outline: 'none',
  boxShadow: '0 1px 6px rgba(32,33,36,0.28)', // Modern soft shadow
  transition: 'all 0.3s',
};

const gridStyle = { 
  display: 'grid', 
  gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', 
  gap: '30px' 
};

const cardStyle = { 
  backgroundColor: '#ffffff',
  borderRadius: '16px', 
  overflow: 'hidden',
  border: '1px solid #dadce0',
  boxShadow: '0 1px 2px rgba(60,64,67,0.3), 0 1px 3px 1px rgba(60,64,67,0.15)',
  display: 'flex',
  flexDirection: 'column',
  transition: 'transform 0.2s ease',
};

const imageWrapper = {
  width: '100%',
  height: '240px',
  overflow: 'hidden',
  backgroundColor: '#f8f9fa',
};

const imageStyle = { 
  width: '100%', 
  height: '100%', 
  objectFit: 'cover',
};

const cardContent = {
  padding: '20px',
  display: 'flex',
  flexDirection: 'column',
  flex: 1,
};

const itemHeader = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'baseline',
  marginBottom: '4px',
};

const itemTitle = {
  fontSize: '18px',
  fontWeight: '600',
  margin: 0,
  color: '#202124',
};

const itemPrice = {
  fontSize: '18px',
  fontWeight: '700',
  color: '#1e8e3e', // Success Green
};

const itemCategory = {
  fontSize: '14px',
  color: '#5f6368',
  margin: '0 0 16px 0',
};

const sellerRow = {
  marginTop: 'auto', // Pushes seller info and button to bottom
  borderTop: '1px solid #f1f3f4',
  paddingTop: '12px',
  marginBottom: '16px',
};

const sellerInfo = { 
  display: 'flex', 
  alignItems: 'center', 
};

const sellerText = {
  color: '#70757a',
  fontSize: '12px',
};

const buyButtonStyle = {
  width: '100%',
  padding: '12px',
  backgroundColor: '#1a73e8', // Consistent Google Blue
  color: 'white',
  border: 'none',
  borderRadius: '8px',
  cursor: 'pointer',
  fontWeight: '600',
  fontSize: '14px',
  transition: 'background-color 0.2s',
};

export default Marketplace;
